body:
Change Verilog emission to not emit an "assign" when in a procedural
region.  Emit a blocking assign instead.

Fixes #751.

The following code (copied from the example in #751):

```mlir
rtl.module @foobar(%clock: i1, %arg1: i1, %arg2: i1, %arg3: i1) {
  sv.always posedge %clock  {
    sv.if %arg1  {
      sv.fatal
    }
    //this forces a common subexpression to be output out-of-line
    %610 = comb.and %arg1, %arg2 : i1
    %611 = comb.and %arg3, %610 : i1
    sv.if %610  {
      sv.fatal
    }
    sv.if %611  {
      sv.fatal
    }
  }
  rtl.output
}
```

Will now produce:

```verilog
module foobar(
  input clock, arg1, arg2, arg3);

  always @(posedge clock) begin
    automatic logic _T;

    if (arg1)
      $fatal;
    _T = arg1 & arg2;
    if (_T)
      $fatal;
    if (arg3 & _T)
      $fatal;
  end // always @(posedge)
endmodule
```

Previously this would produce:

```verilog
module foobar(
  input clock, arg1, arg2, arg3);

  always @(posedge clock) begin
    automatic logic _T;

    if (arg1)
      $fatal;
    assign _T = arg1 & arg2;
    if (_T)
      $fatal;
    if (arg3 & _T)
      $fatal;
  end // always @(posedge)
endmodule
```
